+/// Generate a complete graph with n vertices
+fn generate_complete_graph(n: usize) -> Vec<(u64, u64, f64)> {
+    let mut edges = Vec::new();
+    for i in 0..n as u64 {
+        for j in (i + 1)..n as u64 {
+            edges.push((i, j, 1.0));
+        }
+    }
+    edges
+}
