+                    |mut idx| {
+                        // Find replacement for middle edge
+                        let u = (n / 2) as u64;
+                        let v = u + 1;
+                        let result = idx.find_replacement(u, v, &tree_adj);
+                        black_box(result)
+                    },
+                    criterion::BatchSize::SmallInput,
