+        (3, 4, 1.0), (4, 5, 1.0), (5, 0, 1.0),
+        (0, 3, 0.5), (1, 4, 0.5), (2, 5, 0.5)
+    ]
+
+    # Compute minimum cut
+    result = compute_min_cut(edges)
+
+    # Create NetworkX graph for visualization
+    G = nx.Graph()
+    for from_node, to_node, weight in edges:
